Select DISTINCT customers.customer_id, customers.customer_name from customers JOIN orders ON customers.customer_id = orders.customer_id Where orders.customer_id IN (SELECT customer_id FROM orders WHERE product_name = 'A') AND orders.customer_id IN (SELECT customer_id FROM orders WHERE product_name = 'B') AND orders.customer_id NOT IN (SELECT customer_id FROM orders WHERE product_name = 'C') ORDER BY customers.customer_name;